<?php
namespace Tests\Unit;
use App\Exceptions\MovieNotFoundException; use App\Services\OmdbMovieService; use Illuminate\Support\Facades\Http; use Tests\TestCase;
class OmdbMovieServiceTest extends TestCase { public function test_it_normalizes_successful_omdb_response(): void { config(['services.omdb.key'=>'test-key','services.omdb.base_url'=>'https://www.omdbapi.com']); Http::fake(['www.omdbapi.com*'=>Http::response(['Title'=>'Dune','Year'=>'2021','Released'=>'22 Oct 2021','Runtime'=>'155 min','Genre'=>'Adventure, Drama','Poster'=>'N/A','imdbRating'=>'8.0','imdbID'=>'tt1160419','Type'=>'movie','Response'=>'True'])]); $movie = app(OmdbMovieService::class)->fetch('tt1160419'); $this->assertSame('tt1160419',$movie['imdb_id']); $this->assertSame('Dune',$movie['title']); $this->assertNull($movie['poster_url']); $this->assertSame('2021-10-22',$movie['released_at']); }
 public function test_it_throws_when_movie_not_found(): void { config(['services.omdb.key'=>'test-key','services.omdb.base_url'=>'https://www.omdbapi.com']); Http::fake(['www.omdbapi.com*'=>Http::response(['Response'=>'False','Error'=>'Movie not found!'])]); $this->expectException(MovieNotFoundException::class); app(OmdbMovieService::class)->fetch('not real'); } }
